    Graph g(type_);
    for (auto& [id, data] : nodes_) g.add_node_with_id(id);
    for_each_edge([&](const Edge& e) {
        if (!is_directed() && e.src > e.dst) return;
        if (e.weight >= min_weight && e.weight <= max_weight) {
